/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Pedido Venda"
//Report Template Source Header if &Context.EmpCod = 0 loadWWPContext.Call(&Context) Endif
For Each ORder EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &AppName = FilFan
&AddressLine1 = &Today.ToFormattedString() + ' ' + &Time.Trim() //FilLogNro.Trim() + ' - ' + FilBai.Trim() + ', '+ FilCidCodNomUfe.Trim()
&AddressLine2 = FilFonNum.Trim() if not FilEml.IsEmpty() if not &AddressLine2.IsEmpty() &AddressLine2 += ' / ' Endif &AddressLine2 += FilEml.Trim() Endif Exit EndFor
Print printTitle End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &FilCod.IsEmpty()
print printBlockFilterFilCod EndIf If not &PedFatFilCod.IsEmpty()
print printBlockFilterPedFatFilCod EndIf If not &PedCod.IsEmpty() print printBlockFilterPedCod EndIf If not &PedSts.IsEmpty() &FilterPedStsValueDescription = &PedSts.EnumerationDescription()
print printBlockFilterPedSts EndIf If not &PedNovStsCod.IsEmpty()
print printBlockFilterPedNovStsCod EndIf If not &PedCliCod.IsEmpty() print printBlockFilterPedCliCod EndIf If not &PedCliRaz.IsEmpty() print printBlockFilterPedCliRaz EndIf If not &PedStsFin.IsEmpty() &FilterPedStsFinValueDescription = &PedStsFin.EnumerationDescription()
print printBlockFilterPedStsFin EndIf If not &PedNovStsFinCod.IsEmpty()
print printBlockFilterPedNovStsFinCod EndIf If not &PedDtaEms.IsEmpty() print printBlockFilterPedDtaEms EndIf If not &PedDtaEms_To.IsEmpty() &PedDtaEms_To_Description = format('%1 (%2)', "Emissão", "à") print printBlockFilterPedDtaEms_To EndIf If not &LctTip.IsEmpty() &FilterLctTipValueDescription = &LctTip.EnumerationDescription()
print printBlockFilterLctTip EndIf If not &LctAtuSal.IsEmpty() &FilterLctAtuSalValueDescription = &LctAtuSal.EnumerationDescription()
print printBlockFilterLctAtuSal EndIf If not &PedBlq.IsEmpty() &FilterPedBlqValueDescription = &PedBlq.EnumerationDescription()
print printBlockFilterPedBlq EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'LCTCOD' &LctCod1.FromString(&GridStateDynamicFilter.Value) If not &LctCod1.IsEmpty() &LctCod = &LctCod1 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector1 = !'PEDDTAFAT' &PedDtaFat1.FromString(&GridStateDynamicFilter.Value) &PedDtaFat_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaFat1.IsEmpty() &FilterPedDtaFatDescription = "Faturado" &PedDtaFat = &PedDtaFat1 print printBlockFilterPedDtaFat EndIf If not &PedDtaFat_To1.IsEmpty() &FilterPedDtaFatDescription = format('%1 (%2)', "Faturado", "até") &PedDtaFat = &PedDtaFat_To1 print printBlockFilterPedDtaFat EndIf Case &DynamicFiltersSelector1 = !'PEDVENCOD' &PedVenCod1.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod1.IsEmpty() &PedVenCod = &PedVenCod1 print printBlockFilterPedVenCod EndIf Case &DynamicFiltersSelector1 = !'PEDVLRBRT' &PedVlrBrt1.FromString(&GridStateDynamicFilter.Value) If not &PedVlrBrt1.IsEmpty() &PedVlrBrt = &PedVlrBrt1 print printBlockFilterPedVlrBrt EndIf Case &DynamicFiltersSelector1 = !'PEDVLRLIQ' &PedVlrLiq1.FromString(&GridStateDynamicFilter.Value) If not &PedVlrLiq1.IsEmpty() &PedVlrLiq = &PedVlrLiq1 print printBlockFilterPedVlrLiq EndIf Case &DynamicFiltersSelector1 = !'PEDRSPCOD' &PedRspCod1.FromString(&GridStateDynamicFilter.Value) If not &PedRspCod1.IsEmpty() &PedRspCod = &PedRspCod1 print printBlockFilterPedRspCod EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'LCTCOD' &LctCod2.FromString(&GridStateDynamicFilter.Value) If not &LctCod2.IsEmpty() &LctCod = &LctCod2 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector2 = !'PEDDTAFAT' &PedDtaFat2.FromString(&GridStateDynamicFilter.Value) &PedDtaFat_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaFat2.IsEmpty() &FilterPedDtaFatDescription = "Faturado" &PedDtaFat = &PedDtaFat2 print printBlockFilterPedDtaFat EndIf If not &PedDtaFat_To2.IsEmpty() &FilterPedDtaFatDescription = format('%1 (%2)', "Faturado", "até") &PedDtaFat = &PedDtaFat_To2 print printBlockFilterPedDtaFat EndIf Case &DynamicFiltersSelector2 = !'PEDVENCOD' &PedVenCod2.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod2.IsEmpty() &PedVenCod = &PedVenCod2 print printBlockFilterPedVenCod EndIf Case &DynamicFiltersSelector2 = !'PEDVLRBRT' &PedVlrBrt2.FromString(&GridStateDynamicFilter.Value) If not &PedVlrBrt2.IsEmpty() &PedVlrBrt = &PedVlrBrt2 print printBlockFilterPedVlrBrt EndIf Case &DynamicFiltersSelector2 = !'PEDVLRLIQ' &PedVlrLiq2.FromString(&GridStateDynamicFilter.Value) If not &PedVlrLiq2.IsEmpty() &PedVlrLiq = &PedVlrLiq2 print printBlockFilterPedVlrLiq EndIf Case &DynamicFiltersSelector2 = !'PEDRSPCOD' &PedRspCod2.FromString(&GridStateDynamicFilter.Value) If not &PedRspCod2.IsEmpty() &PedRspCod = &PedRspCod2 print printBlockFilterPedRspCod EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'LCTCOD' &LctCod3.FromString(&GridStateDynamicFilter.Value) If not &LctCod3.IsEmpty() &LctCod = &LctCod3 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector3 = !'PEDDTAFAT' &PedDtaFat3.FromString(&GridStateDynamicFilter.Value) &PedDtaFat_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaFat3.IsEmpty() &FilterPedDtaFatDescription = "Faturado" &PedDtaFat = &PedDtaFat3 print printBlockFilterPedDtaFat EndIf If not &PedDtaFat_To3.IsEmpty() &FilterPedDtaFatDescription = format('%1 (%2)', "Faturado", "até") &PedDtaFat = &PedDtaFat_To3 print printBlockFilterPedDtaFat EndIf Case &DynamicFiltersSelector3 = !'PEDVENCOD' &PedVenCod3.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod3.IsEmpty() &PedVenCod = &PedVenCod3 print printBlockFilterPedVenCod EndIf Case &DynamicFiltersSelector3 = !'PEDVLRBRT' &PedVlrBrt3.FromString(&GridStateDynamicFilter.Value) If not &PedVlrBrt3.IsEmpty() &PedVlrBrt = &PedVlrBrt3 print printBlockFilterPedVlrBrt EndIf Case &DynamicFiltersSelector3 = !'PEDVLRLIQ' &PedVlrLiq3.FromString(&GridStateDynamicFilter.Value) If not &PedVlrLiq3.IsEmpty() &PedVlrLiq = &PedVlrLiq3 print printBlockFilterPedVlrLiq EndIf Case &DynamicFiltersSelector3 = !'PEDRSPCOD' &PedRspCod3.FromString(&GridStateDynamicFilter.Value) If not &PedRspCod3.IsEmpty() &PedRspCod = &PedRspCod3 print printBlockFilterPedRspCod EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod (PedCod) when &OrderedBy = 1 order EmpCod FilCod PedCod when &OrderedBy = 2 order EmpCod FilCod PedCliRaz PedNovCliRaz when &OrderedBy = 3 order PedCod when &OrderedBy = 4 AND &OrderedDsc = False order (PedCod) when &OrderedBy = 4 AND &OrderedDsc = True order PedDtaEms when &OrderedBy = 5 AND &OrderedDsc = False order (PedDtaEms) when &OrderedBy = 5 AND &OrderedDsc = True order PedDtaPrv when &OrderedBy = 6 AND &OrderedDsc = False order (PedDtaPrv) when &OrderedBy = 6 AND &OrderedDsc = True order PedDtaRetCon when &OrderedBy = 7 AND &OrderedDsc = False order (PedDtaRetCon) when &OrderedBy = 7 AND &OrderedDsc = True order PedDtaFat when &OrderedBy = 8 AND &OrderedDsc = False order (PedDtaFat) when &OrderedBy = 8 AND &OrderedDsc = True order PedVlrBrt when &OrderedBy = 9 AND &OrderedDsc = False order (PedVlrBrt) when &OrderedBy = 9 AND &OrderedDsc = True order PedVlrLiq when &OrderedBy = 10 AND &OrderedDsc = False order (PedVlrLiq) when &OrderedBy = 10 AND &OrderedDsc = True order LctCod when &OrderedBy = 11 AND &OrderedDsc = False order (LctCod) when &OrderedBy = 11 AND &OrderedDsc = True order PedVenCod when &OrderedBy = 12 AND &OrderedDsc = False order (PedVenCod) when &OrderedBy = 12 AND &OrderedDsc = True
using DSwwPedidoBalcao(&FilCod, &PedFatFilCod, &PedCod, &PedSts, &PedNovStsCod, &PedCliCod , &PedCliRaz, &PedStsFin, &PedNovStsFinCod, &PedDtaEms, &PedDtaEms_To, &LctTip , &LctAtuSal, &PedBlq, &DynamicFiltersSelector1, &LctCod1, &PedDtaFat1, &PedDtaFat_To1 , &PedVenCod1, &PedVlrBrt1, &PedVlrLiq1, &PedRspCod1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2 , &LctCod2, &PedDtaFat2, &PedDtaFat_To2, &PedVenCod2, &PedVlrBrt2, &PedVlrLiq2 , &PedRspCod2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &LctCod3, &PedDtaFat3, &PedDtaFat_To3 , &PedVenCod3, &PedVlrBrt3, &PedVlrLiq3, &PedRspCod3)
if PedCliCodRaz_Nov.Length() > 30 &PedCliCodRaz_Nov = substr(PedCliCodRaz_Nov, 1, 30) + '...' Else &PedCliCodRaz_Nov = PedCliCodRaz_Nov EndIf
If PedStsFinIsPar = true &AuxFin = 'PAR.' Else &AuxFin = UPPER(Substr(PedStsFin.EnumerationDescription(), 1,3)) Endif
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wwPedidoBalcaoGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wwPedidoBalcaoGridState")) Else &GridState.FromXml(&Session.Get(!"wwPedidoBalcaoGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDFATFILCOD" &PedFatFilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCOD" &PedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTS" &PedSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDNOVSTSCOD" &PedNovStsCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCLICOD" &PedCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCLIRAZ" &PedCliRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTSFIN" &PedStsFin.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDNOVSTSFINCOD" &PedNovStsFinCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDDTAEMS" &PedDtaEms.FromString(&GridStateFilterValue.Value) &PedDtaEms_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"LCTTIP" &LctTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"LCTATUSAL" &LctAtuSal.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDBLQ" &PedBlq.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
